import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Product } from '../../core/models';

/**
 * Products list + create/edit via `?modal=new` / `?edit=:id`. Mutations gated
 * to the admin role only. Money entered/displayed in dollars but stored as
 * integer cents. service_agent wires ApiService product methods.
 */
@Component({
  selector: 'app-products',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './products.component.html',
  styleUrl: './products.component.css',
})
export class ProductsComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly saving = signal(false);

  readonly products = signal<Product[]>([
    { id: 'p1', sku: 'WID-001', name: 'Widget', costCents: 450, priceCents: 999, onHand: 120 },
    { id: 'p2', sku: 'GAD-002', name: 'Gadget', costCents: 1200, priceCents: 2499, onHand: 64 },
    { id: 'p3', sku: 'SPR-003', name: 'Sprocket', costCents: 80, priceCents: 249, onHand: 340 },
    { id: 'p4', sku: 'BLT-004', name: 'Bolt (pack of 50)', costCents: 320, priceCents: 699, onHand: 210 },
    { id: 'p5', sku: null, name: 'Assembly Kit', costCents: 5400, priceCents: 8900, onHand: 22 },
  ]);

  readonly canEdit = computed(() => this.auth.isAdmin());

  readonly modalOpen = signal(false);
  readonly editingId = signal<string | null>(null);
  // Form uses dollar strings for money; converted to cents on save.
  form = { sku: '', name: '', cost: '', price: '', onHand: '0' };

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.route.queryParams.subscribe((q) => {
      if (q['modal'] === 'new' && this.canEdit()) {
        this.openCreate();
      } else if (q['edit']) {
        this.openEdit(q['edit']);
      } else {
        this.modalOpen.set(false);
      }
    });
  }

  money(cents: number): string {
    return (cents / 100).toLocaleString(undefined, { style: 'currency', currency: 'USD' });
  }

  openCreate(): void {
    this.editingId.set(null);
    this.form = { sku: '', name: '', cost: '', price: '', onHand: '0' };
    this.modalOpen.set(true);
  }

  openEdit(id: string): void {
    const p = this.products().find((x) => x.id === id);
    if (!p) return;
    this.editingId.set(id);
    this.form = {
      sku: p.sku ?? '',
      name: p.name,
      cost: (p.costCents / 100).toFixed(2),
      price: (p.priceCents / 100).toFixed(2),
      onHand: String(p.onHand),
    };
    this.modalOpen.set(true);
  }

  close(): void {
    this.router.navigate([], { queryParams: {} });
    this.modalOpen.set(false);
  }

  save(): void {
    if (!this.form.name) {
      this.error.set('Name is required.');
      return;
    }
    this.saving.set(true);
    const patch: Partial<Product> = {
      sku: this.form.sku || null,
      name: this.form.name,
      costCents: Math.round(parseFloat(this.form.cost || '0') * 100),
      priceCents: Math.round(parseFloat(this.form.price || '0') * 100),
      onHand: parseInt(this.form.onHand || '0', 10),
    };
    const id = this.editingId();
    if (id) {
      this.products.update((list) =>
        list.map((p) => (p.id === id ? { ...p, ...patch } as Product : p)),
      );
    } else {
      this.products.update((list) => [
        { id: 'p' + (list.length + 1), ...patch } as Product,
        ...list,
      ]);
    }
    this.saving.set(false);
    this.close();
  }

  remove(id: string, ev: Event): void {
    ev.stopPropagation();
    if (!this.canEdit()) return;
    this.products.update((list) => list.filter((p) => p.id !== id));
  }
}
